#include <bits/stdc++.h>
using namespace std;

const int N=102,mod=20091119;

char s[N];
int f[N][10];
int n,a[N];

void init(){
    for(int i=0;i<=9;i++)
        f[1][i]=f[2][i]=1;
    for(int i=3;i<N;i++)
        for(int j=0;j<=9;j++)
            for(int k=0;k<=9;k++)
                f[i][j]=(f[i][j]+f[i-2][k])%mod;
}

int solve(){
    n=strlen(s+1);
    for(int i=1;i<=n;i++)
        a[i]=s[i]-'0';
    int res=0;
    for(int i=1;i<=(n+1)/2;i++){
        for(int j=(i==1);j<a[i];j++)
            res=(res+f[n-2*i+2][j])%mod;
    }
    bool flag=true;
    for(int i=(n+1)/2+1;i<=n;i++)
    	if(a[n+1-i]!=a[i]){
            if(a[n+1-i]>a[i])
                flag=false;
            break;
        }
    if(flag) res=(res+1)%mod;
    for(int i=1;i<n;i++)
        for(int j=1;j<=9;j++)
            res=(res+f[i][j])%mod;
    return res;
}

int main(){
    scanf("%s",s+1);
    init();
    printf("%d",solve());
    return 0;
}
